frame_eqs:
dec_m = pow (0.8, 30/fps);
dec_s = pow (0.9, 30/fps);
vol = (bass+mid+treb)/3;
vol_ = dec_m * vol_ + (1-dec_m)*vol;
avg = avg*dec_s + vol*(1-dec_s);
is_beat = above(vol, 1*avg+2*peak) * above (time, t0+.2);
t0 = is_beat*time + (1-is_beat)*t0;
peak = is_beat * vol + (1-is_beat)*peak*dec_m;
index = (index + is_beat) %8;
index2 = (index2 + is_beat*bnot(index)) %8;

trig = is_beat*(index==0);
t1 = t1+trig;

ran1 = dec_m * ran1 + (1-dec_m)*cos(3.14/6*t1);
ran2 = dec_m * ran2 + (1-dec_m)*sin(3.14/6*t1);
ran3 = dec_m * ran3 + (1-dec_m)*sin(3.14/5*t1);
q1 = ran1; q2 = ran2; q3 = ran3;

n = 0;
p1 *= .9; p2 = 0; p3 = 0;
mx = 0; my = 0; mz = 0;
vol2 = min(vol,2);
vol2 = sqrt(vol);
k5 = 1 / (rand(10)+.2);
loop (shapes,
sa = n/shapes;
p1 =  p1+.15*sin(sa*(vol-1)*200+time*.1)*vol;
p2 = p2-p1*vol*k5;
x1 += sin(p2)*sa*.006*vol;
y1 += cos(p2)*sa*.006*vol;
z1 += cos(p1*.03)*.005*vol;

mx += x1; my += y1; mz += z1;
x1 = atan(x1/16)*16;
y1 = atan(y1/16)*16;
z1 = atan(z1/16)*16;
//z1 = 1;
gmegabuf(n*4) =   x1;
gmegabuf(n*4+1) = y1;
gmegabuf(n*4+2) = z1;
n +=1;
);

trel = trel + vol_/fps*.3;
q4 = min(max(0,4*sin(trel)),1)*-.2;
mzoom = if(trig,.1*vol2*(rand(10)>=3),mzoom);
mzoom_ = mzoom_*dec_m + (1-dec_m)*mzoom;
q4 = mzoom_;
q5 = vol >= vol_;

monitor = q5;
q6=aspecty;
q27 = index;
q28 = index2;
q24 = is_beat;
q30 = min(1,.05/mzoom);;

trig1 = is_beat*(index%2);
pk = if (trig1,1,pk*dec_m);
ran5 = if(trig1, rand(1), ran5);

q22 = pk * pk * (frame%2);
q22 = pk==1;
q23 = ran5;

